sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {
    var requesterSysId = event.parm2;  // Requester's sys_id from event

    if (!requesterSysId) {
        template.print('<p>No requester found - skipping previous queries table.</p>');
        return;
    }

    var gr = new GlideRecord('x_1839224_chroma_0_chromatech_customer_queries');  // Your table name; adjust if different
    gr.addQuery('requester', requesterSysId);  // Filter by requester field
    gr.addQuery('sys_id', '!=', event.parm1);  // Exclude the new record
    gr.orderByDesc('sys_created_on');  // Show newest first
    gr.query();

    if (!gr.hasNext()) {
        template.print('<p>You have no previous queries.</p>');
        return;
    }

    template.print('<h3>Your Previous Queries</h3>');
    template.print('<table border="1" cellpadding="5" style="border-collapse: collapse; width: 100%;">');
    template.print('<tr><th>Number</th><th>Short Description</th><th>State</th><th>Priority</th><th>Assigned To</th></tr>');

    while (gr.next()) {
        template.print('<tr>');
        template.print('<td>' + (gr.number || 'N/A') + '</td>');
        template.print('<td>' + (gr.short_description || 'N/A') + '</td>');
        template.print('<td>' + (gr.state ? gr.state.getDisplayValue() : 'N/A') + '</td>');  // Adjust 'state' if it's 'issue_state'
        template.print('<td>' + (gr.priority ? gr.priority.getDisplayValue() : 'N/A') + '</td>');
        template.print('<td>' + (gr.assigned_to ? gr.assigned_to.getDisplayValue() : 'N/A') + '</td>');
        template.print('</tr>');
    }

    template.print('</table>');
})(current, template, email, email_action, event);
